     1→const express = require('express');
     2→const pool = require('../lib/db');
     3→const { authMiddleware } = require('../lib/auth');
     4→const { generateInterviewQuestions, analyzeInterviewResponse, generateOverallFeedback, generateInterviewCoaching, analyzeVideoInterviewResponse, analyzeVideoPresentation, analyzeVoiceQuality, generateQuestionBank, conductInterviewTurn, generateSessionFeedback, textToSpeech, transcribeAudioWithWhisper, aiProvider } = require('../lib/polsia-ai');
     5→const crypto = require('crypto');
     6→const omniscoreService = require('../services/omniscore');
     7→const multer = require('multer');
     8→const fetch = require('node-fetch');
     9→const FormData = require('form-data');
    10→
    11→const router = express.Router();
    12→const upload = multer({ storage: multer.memoryStorage() });
    13→
    14→// Helper: Race a promise against a timeout to prevent hanging when AI providers are slow.
    15→// The AI provider chain can take 9×15s = 135s worst case; Render kills requests at ~30s.
    16→// This ensures we hit the scripted fallback BEFORE the request is killed.
    17→function withTimeout(promise, ms, label = 'Operation') {
    18→  return Promise.race([
    19→    promise,
    20→    new Promise((_, reject) => setTimeout(() => {
    21→      reject(new Error(`${label} timed out after ${ms}ms`));
    22→    }, ms))
    23→  ]);
    24→}
    25→
    26→// Fallback questions if AI generation fails
    27→const FALLBACK_QUESTIONS = [
    28→  {
    29→    question: 'Tell me about yourself and why you are interested in this role.',
    30→    category: 'behavioral',
    31→    difficulty: 'easy',
    32→    key_points: ['Self-introduction', 'Relevant experience', 'Career goals', 'Enthusiasm']
    33→  },
    34→  {
    35→    question: 'Describe a challenging project you worked on. What was your role and how did you handle obstacles?',
    36→    category: 'behavioral',
    37→    difficulty: 'medium',
    38→    key_points: ['Problem-solving', 'Resilience', 'Technical skills', 'Teamwork']
    39→  },
    40→  {
    41→    question: 'How do you prioritize your work when you have multiple deadlines?',
    42→    category: 'situational',
    43→    difficulty: 'medium',
    44→    key_points: ['Time management', 'Organization', 'Communication', 'Prioritization frameworks']
    45→  },
    46→  {
    47→    question: 'Tell me about a time you received constructive criticism. How did you respond?',
    48→    category: 'behavioral',
    49→    difficulty: 'medium',
    50→    key_points: ['Self-awareness', 'Growth mindset', 'Professional maturity', 'Adaptability']
    51→  },
    52→  {
    53→    question: 'Where do you see yourself in 5 years, and how does this role fit into your career plan?',
    54→    category: 'situational',
    55→    difficulty: 'easy',
    56→    key_points: ['Career vision', 'Ambition', 'Role alignment', 'Long-term thinking']
    57→  }
    58→];
    59→
    60→// Start a new interview
    61→router.post('/start', authMiddleware, async (req, res) => {
    62→  try {
    63→    const { job_id, job_title, job_description, interview_type = 'mock' } = req.body;
    64→
    65→    // Generate questions using AI with fallback
    66→    let questions;
    67→    try {
    68→      questions = await generateInterviewQuestions(
    69→        job_title || 'Software Developer',
    70→        job_description,
    71→        5
    72→      );
    73→      console.log('AI generated', questions.length, 'interview questions');
    74→    } catch (aiErr) {
    75→      console.error('AI question generation failed, using fallback questions:', aiErr.message);
    76→      questions = FALLBACK_QUESTIONS;
    77→    }
    78→
    79→    // Validate questions array
    80→    if (!questions || !Array.isArray(questions) || questions.length === 0) {
    81→      console.warn('Invalid questions from AI, using fallback');
    82→      questions = FALLBACK_QUESTIONS;
    83→    }
    84→
    85→    // Create interview record
    86→    const result = await pool.query(
    87→      `INSERT INTO interviews (user_id, job_id, interview_type, questions, status)
    88→       VALUES ($1, $2, $3, $4, 'in_progress')
    89→       RETURNING *`,
    90→      [req.user.id, job_id, interview_type, JSON.stringify(questions)]
    91→    );
    92→
    93→    // Track mock interview start
    94→    try {
    95→      await pool.query(
    96→        'INSERT INTO events (event_type, user_id, metadata) VALUES ($1, $2, $3)',
    97→        ['mock_interview_start', req.user.id, JSON.stringify({ interview_type, job_id })]
    98→      );
    99→    } catch (e) {
   100→      console.error('Failed to log interview start event:', e);
   101→    }
   102→
   103→    res.json({
   104→      success: true,
   105→      interview: result.rows[0],
   106→      questions: questions.map((q, i) => ({
   107→        index: i,
   108→        question: q.question,
   109→        category: q.category,
   110→        difficulty: q.difficulty
   111→      }))
   112→    });
   113→  } catch (err) {
   114→    console.error('Start interview error:', err);
   115→    res.status(500).json({ error: 'Failed to start interview' });
   116→  }
   117→});
   118→
   119→// Submit response to a question
   120→router.post('/:id/respond', authMiddleware, async (req, res) => {
   121→  try {
   122→    const { question_index, response_text, video_url } = req.body;
   123→
   124→    // Get interview
   125→    const interview = await pool.query(
   126→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   127→      [req.params.id, req.user.id]
   128→    );
   129→
   130→    if (interview.rows.length === 0) {
   131→      return res.status(404).json({ error: 'Interview not found' });
   132→    }
   133→
   134→    const interviewData = interview.rows[0];
   135→    const questions = interviewData.questions;
   136→    const question = questions[question_index];
   137→
   138→    if (!question) {
   139→      return res.status(400).json({ error: 'Invalid question index' });
   140→    }
   141→
   142→    // Analyze response with AI
   143→    const analysis = await analyzeInterviewResponse(
   144→      question.question,
   145→      response_text,
   146→      question.key_points || [],
   147→      { subscriptionId: req.user.stripe_subscription_id }
   148→    );
   149→
   150→    // Update responses array
   151→    const responses = interviewData.responses || [];
   152→    responses[question_index] = {
   153→      question_index,
   154→      response_text,
   155→      video_url,
   156→      analysis,
   157→      submitted_at: new Date().toISOString()
   158→    };
   159→
   160→    // Update video URLs if provided
   161→    const videoUrls = interviewData.video_urls || [];
   162→    if (video_url) {
   163→      videoUrls[question_index] = video_url;
   164→    }
   165→
   166→    // Update responses - use updated_at if column exists, fallback gracefully
   167→    try {
   168→      await pool.query(
   169→        `UPDATE interviews SET responses = $1, video_urls = $2, updated_at = NOW()
   170→         WHERE id = $3`,
   171→        [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   172→      );
   173→    } catch (updateErr) {
   174→      // Fallback if updated_at column doesn't exist yet (pre-migration)
   175→      if (updateErr.message && updateErr.message.includes('updated_at')) {
   176→        console.warn('updated_at column missing, updating without it');
   177→        await pool.query(
   178→          `UPDATE interviews SET responses = $1, video_urls = $2
   179→           WHERE id = $3`,
   180→          [JSON.stringify(responses), JSON.stringify(videoUrls), req.params.id]
   181→        );
   182→      } else {
   183→        throw updateErr;
   184→      }
   185→    }
   186→
   187→    res.json({
   188→      success: true,
   189→      analysis,
   190→      questions_remaining: questions.length - responses.filter(r => r).length
   191→    });
   192→  } catch (err) {
   193→    console.error('Submit response error:', err);
   194→    res.status(500).json({ error: 'Failed to submit response' });
   195→  }
   196→});
   197→
   198→// Complete interview and get overall feedback
   199→router.post('/:id/complete', authMiddleware, async (req, res) => {
   200→  try {
   201→    const interview = await pool.query(
   202→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   203→      [req.params.id, req.user.id]
   204→    );
   205→
   206→    if (interview.rows.length === 0) {
   207→      return res.status(404).json({ error: 'Interview not found' });
   208→    }
   209→
   210→    const interviewData = interview.rows[0];
   211→    const responses = interviewData.responses || [];
   212→    const validResponses = responses.filter(r => r && r.analysis);
   213→
   214→    if (validResponses.length === 0) {
   215→      return res.status(400).json({ error: 'No responses to evaluate' });
   216→    }
   217→
   218→    // Generate overall feedback
   219→    const overallFeedback = await generateOverallFeedback(
   220→      validResponses.map(r => r.analysis),
   221→      { subscriptionId: req.user.stripe_subscription_id }
   222→    );
   223→
   224→    // Calculate duration
   225→    const startTime = new Date(interviewData.created_at);
   226→    const duration = Math.floor((Date.now() - startTime.getTime()) / 1000);
   227→
   228→    // Update interview record
   229→    await pool.query(
   230→      `UPDATE interviews SET
   231→        status = 'completed',
   232→        ai_feedback = $1,
   233→        overall_score = $2,
   234→        duration_seconds = $3,
   235→        completed_at = NOW()
   236→       WHERE id = $4`,
   237→      [JSON.stringify(overallFeedback), overallFeedback.overall_score, duration, req.params.id]
   238→    );
   239→
   240→    // Update OmniScore with interview results
   241→    let omniscoreUpdate = null;
   242→    try {
   243→      omniscoreUpdate = await omniscoreService.addInterviewComponent(
   244→        req.user.id,
   245→        req.params.id,
   246→        overallFeedback.overall_score
   247→      );
   248→
   249→      // Update role-specific score if job title is available
   250→      if (interviewData.job_id) {
   251→        const job = await pool.query('SELECT title FROM jobs WHERE id = $1', [interviewData.job_id]);
   252→        if (job.rows.length > 0) {
   253→          await omniscoreService.updateRoleScore(
   254→            req.user.id,
   255→            job.rows[0].title,
   256→            overallFeedback.overall_score
   257→          );
   258→        }
   259→      }
   260→    } catch (scoreErr) {
   261→      console.error('OmniScore update error:', scoreErr);
   262→      // Don't fail the request if OmniScore update fails
   263→    }
   264→
   265→    res.json({
   266→      success: true,
   267→      overall_feedback: overallFeedback,
   268→      duration_seconds: duration,
   269→      response_count: validResponses.length,
   270→      omniscore: omniscoreUpdate
   271→    });
   272→  } catch (err) {
   273→    console.error('Complete interview error:', err);
   274→    res.status(500).json({ error: 'Failed to complete interview' });
   275→  }
   276→});
   277→
   278→// Get interview history
   279→router.get('/history', authMiddleware, async (req, res) => {
   280→  try {
   281→    const { limit = 10, offset = 0 } = req.query;
   282→
   283→    const result = await pool.query(
   284→      `SELECT i.*, j.title as job_title, j.company as job_company
   285→       FROM interviews i
   286→       LEFT JOIN jobs j ON i.job_id = j.id
   287→       WHERE i.user_id = $1
   288→       ORDER BY i.created_at DESC
   289→       LIMIT $2 OFFSET $3`,
   290→      [req.user.id, limit, offset]
   291→    );
   292→
   293→    res.json({ interviews: result.rows });
   294→  } catch (err) {
   295→    console.error('Get history error:', err);
   296→    res.status(500).json({ error: 'Failed to fetch history' });
   297→  }
   298→});
   299→
   300→// Get interview details
   301→router.get('/:id', authMiddleware, async (req, res) => {
   302→  try {
   303→    const result = await pool.query(
   304→      `SELECT i.*, j.title as job_title, j.company as job_company
   305→       FROM interviews i
   306→       LEFT JOIN jobs j ON i.job_id = j.id
   307→       WHERE i.id = $1 AND i.user_id = $2`,
   308→      [req.params.id, req.user.id]
   309→    );
   310→
   311→    if (result.rows.length === 0) {
   312→      return res.status(404).json({ error: 'Interview not found' });
   313→    }
   314→
   315→    res.json({ interview: result.rows[0] });
   316→  } catch (err) {
   317→    console.error('Get interview error:', err);
   318→    res.status(500).json({ error: 'Failed to fetch interview' });
   319→  }
   320→});
   321→
   322→// Upload video for interview response
   323→router.post('/upload-video', authMiddleware, upload.single('video'), async (req, res) => {
   324→  try {
   325→    if (!req.file) {
   326→      return res.status(400).json({ error: 'No video file provided' });
   327→    }
   328→
   329→    const { interview_id, question_index } = req.body;
   330→
   331→    if (!interview_id || question_index === undefined) {
   332→      return res.status(400).json({ error: 'Missing interview_id or question_index' });
   333→    }
   334→
   335→    // Verify interview belongs to user
   336→    const interview = await pool.query(
   337→      'SELECT * FROM interviews WHERE id = $1 AND user_id = $2',
   338→      [interview_id, req.user.id]
   339→    );
   340→
   341→    if (interview.rows.length === 0) {
   342→      return res.status(404).json({ error: 'Interview not found' });
   343→    }
   344→
