  1184→// Submit a response in a mock interview — AI responds conversationally
  1185→router.post('/mock/:sessionId/respond', authMiddleware, async (req, res) => {
  1186→  try {
  1187→    const { response_text } = req.body;
  1188→    const sessionId = req.params.sessionId;
  1189→
  1190→    if (!response_text || response_text.trim().length < 10) {
  1191→      return res.status(400).json({ error: 'Response too short. Please elaborate on your answer.' });
  1192→    }
  1193→
  1194→    // Get session
  1195→    const sessionResult = await pool.query(
  1196→      'SELECT * FROM mock_interview_sessions WHERE id = $1 AND user_id = $2 AND status = $3',
  1197→      [sessionId, req.user.id, 'in_progress']
  1198→    );
  1199→
  1200→    if (sessionResult.rows.length === 0) {
  1201→      return res.status(404).json({ error: 'Session not found or already completed' });
  1202→    }
  1203→
  1204→    const session = sessionResult.rows[0];
  1205→    const conversation = session.conversation || [];
  1206→    const questionIds = session.question_ids || [];
  1207→
  1208→    // Get base questions from bank
  1209→    const questionsResult = await pool.query(
  1210→      'SELECT * FROM question_bank WHERE id = ANY($1)',
  1211→      [questionIds]
  1212→    );
  1213→    // Maintain order from questionIds
  1214→    const questionMap = {};
  1215→    questionsResult.rows.forEach(q => { questionMap[q.id] = q; });
  1216→    const baseQuestions = questionIds.map(id => questionMap[id]).filter(Boolean);
  1217→
  1218→    // Add candidate response to conversation
  1219→    const candidateMessage = {
  1220→      role: 'candidate',
  1221→      text: response_text.trim(),
  1222→      timestamp: new Date().toISOString()
  1223→    };
  1224→    conversation.push(candidateMessage);
  1225→
  1226→    // AI generates next interviewer turn (with fallback on failure)
  1227→    // BUG FIX: Wrap with 20s overall timeout — the LLM chain can take 135s (9 providers × 15s each),
  1228→    // but Render kills the request at ~30s. Without this, the scripted fallback never fires.
  1229→    let aiTurn;
  1230→    try {
  1231→      aiTurn = await withTimeout(
  1232→        conductInterviewTurn(
  1233→          conversation,
  1234→          baseQuestions,
  1235→          session.current_question_index,
  1236→          session.target_role,
  1237→          { subscriptionId: req.user.stripe_subscription_id }
  1238→        ),
  1239→        20000,
  1240→        'Interview AI turn generation'
  1241→      );
  1242→    } catch (aiErr) {
  1243→      console.warn(`[mock] AI turn generation failed (${aiErr.message}), using scripted fallback`);
  1244→      // Scripted fallback: acknowledge answer and move to next question from bank
  1245→      const nextIdx = session.current_question_index + 1;
  1246→      const nextQ = baseQuestions[nextIdx];
  1247→      const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1248→      if (nextQ && candidateTurnCount < 8) {
  1249→        aiTurn = {
  1250→          reaction: "Thank you for that response. That's helpful context.",
  1251→          action: 'transition',
  1252→          question: nextQ.question_text,
  1253→          score_hint: null,
  1254→          notes: 'AI unavailable — scripted transition'
  1255→        };
  1256→      } else {
  1257→        aiTurn = {
  1258→          reaction: "Thank you for sharing all of that. I think we've covered a good range of topics.",
  1259→          action: 'wrap_up',
  1260→          question: "Is there anything else you'd like to add before we wrap up?",
  1261→          score_hint: null,
  1262→          notes: 'AI unavailable — scripted wrap-up'
  1263→        };
  1264→      }
  1265→    }
  1266→
  1267→    // Build interviewer message
  1268→    let interviewerText = aiTurn.reaction || '';
  1269→    if (aiTurn.question) {
  1270→      interviewerText += (interviewerText ? '\n\n' : '') + aiTurn.question;
  1271→    }
  1272→
  1273→    const interviewerMessage = {
  1274→      role: 'interviewer',
  1275→      text: interviewerText,
  1276→      action: aiTurn.action || 'transition',
  1277→      score_hint: aiTurn.score_hint || null,
  1278→      notes: aiTurn.notes || null,
  1279→      timestamp: new Date().toISOString()
  1280→    };
  1281→    conversation.push(interviewerMessage);
  1282→
  1283→    // Update session
  1284→    const isWrappingUp = aiTurn.action === 'wrap_up';
  1285→    const isTransition = aiTurn.action === 'transition';
  1286→    const newQuestionIndex = isTransition
  1287→      ? Math.min(session.current_question_index + 1, baseQuestions.length)
  1288→      : session.current_question_index;
  1289→    const newFollowUps = (aiTurn.action === 'follow_up' || aiTurn.action === 'challenge')
  1290→      ? (session.follow_ups_asked || 0) + 1
  1291→      : session.follow_ups_asked || 0;
  1292→
  1293→    // Increment times_used for the new question if transitioning
  1294→    if (isTransition && newQuestionIndex < baseQuestions.length) {
  1295→      const nextQ = baseQuestions[newQuestionIndex];
  1296→      if (nextQ) {
  1297→        await pool.query('UPDATE question_bank SET times_used = times_used + 1 WHERE id = $1', [nextQ.id]);
  1298→      }
  1299→    }
  1300→
  1301→    await pool.query(
  1302→      `UPDATE mock_interview_sessions
  1303→       SET conversation = $1, current_question_index = $2,
  1304→           questions_asked = $3, follow_ups_asked = $4
  1305→       WHERE id = $5`,
  1306→      [
  1307→        JSON.stringify(conversation),
  1308→        newQuestionIndex,
  1309→        isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1310→        newFollowUps,
  1311→        sessionId
  1312→      ]
  1313→    );
  1314→
  1315→    // BUG FIX: Pre-generate feedback in background after 3+ candidate turns
  1316→    // This dramatically reduces wait time when user clicks "End"
  1317→    const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1318→    if (candidateTurnCount >= 3 && !isWrappingUp) {
