  1328→        })
  1329→        .catch(err => console.warn('[mock] Background feedback generation failed:', err.message));
  1330→    }
  1331→
  1332→    res.json({
  1333→      success: true,
  1334→      interviewer_message: interviewerMessage,
  1335→      action: aiTurn.action,
  1336→      questions_asked: isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1337→      is_wrapping_up: isWrappingUp
  1338→    });
  1339→  } catch (err) {
  1340→    console.error('Mock interview respond error:', err);
  1341→    res.status(500).json({ error: 'Failed to process response. Please try again.' });
  1342→  }
  1343→});
