  1420→    }
  1421→
  1422→    // Step 2: Save and return text feedback immediately
  1423→    await pool.query(
  1424→      `UPDATE mock_interview_sessions
  1425→       SET status = 'completed', overall_score = $1, overall_feedback = $2, completed_at = NOW()
  1426→       WHERE id = $3`,
  1427→      [feedback.overall_score || 5, JSON.stringify(feedback), sessionId]
  1428→    );
  1429→
  1430→    // Save as practice_session for stats
  1431→    try {
  1432→      await pool.query(
  1433→        `INSERT INTO practice_sessions
  1434→         (user_id, question_id, question, category, response_text, score, coaching_data, created_at)
  1435→         VALUES ($1, $2, $3, $4, $5, $6, $7, NOW())`,
  1436→        [
  1437→          req.user.id,
  1438→          `mock-${sessionId}`,
  1439→          `Mock Interview: ${session.target_role}`,
  1440→          'mock_interview',
  1441→          candidateText,
  1442→          Math.round(feedback.overall_score || 5),
  1443→          JSON.stringify(feedback)
  1444→        ]
  1445→      );
  1446→    } catch (psErr) {
  1447→      console.error('Failed to save mock session to practice_sessions:', psErr.message);
  1448→    }
  1449→
  1450→    // Return feedback to user IMMEDIATELY (no waiting for video/voice analysis)
  1451→    res.json({
  1452→      success: true,
  1453→      feedback,
  1454→      session: {
  1455→        id: session.id,
  1456→        target_role: session.target_role,
  1457→        questions_asked: session.questions_asked,
  1458→        follow_ups_asked: session.follow_ups_asked,
  1459→        duration_minutes: Math.round(durationSeconds / 60)
  1460→      }
  1461→    });
  1462→
  1463→    // Step 3: Run video/voice analysis in BACKGROUND (fire and forget)
  1464→    // Results get saved to DB — user can see them on next page load or refresh
  1465→    const bgSessionId = sessionId;
  1466→    const bgUserId = req.user.id;
  1467→    (async () => {
  1468→      try {
  1469→        const bgPromises = [];
  1470→        if (frames && Array.isArray(frames) && frames.length > 0) {
  1471→          console.log(`[mock-end-bg] Running background body language analysis with ${frames.length} frames`);
  1472→          bgPromises.push(analyzeVideoPresentation(frames, options).catch(e => { console.warn('[mock-end-bg] Video analysis failed:', e.message); return null; }));
  1473→        } else {
  1474→          bgPromises.push(Promise.resolve(null));
  1475→        }
  1476→        if (candidateText.length > 20) {
  1477→          console.log(`[mock-end-bg] Running background voice quality analysis`);
  1478→          bgPromises.push(analyzeVoiceQuality(candidateText, durationSeconds, options).catch(e => { console.warn('[mock-end-bg] Voice analysis failed:', e.message); return null; }));
  1479→        } else {
  1480→          bgPromises.push(Promise.resolve(null));
  1481→        }
  1482→
  1483→        const [videoAnalysis, voiceAnalysis] = await Promise.all(bgPromises);
  1484→
  1485→        // Merge into feedback
  1486→        if (videoAnalysis) {
  1487→          feedback.presentation = {
  1488→            score: videoAnalysis.overall_presentation || 5,
  1489→            eye_contact: videoAnalysis.eye_contact || { score: 5, feedback: '' },
  1490→            facial_expressions: videoAnalysis.facial_expressions || { score: 5, feedback: '' },
  1491→            body_language: videoAnalysis.body_language || { score: 5, feedback: '' },
  1492→            professional_appearance: videoAnalysis.professional_appearance || { score: 5, feedback: '' },
  1493→            summary: videoAnalysis.summary || ''
  1494→          };
  1495→        }
  1496→        if (voiceAnalysis) {
  1497→          feedback.voice_analysis = voiceAnalysis;
  1498→        }
  1499→
  1500→        // Recalculate score with presentation/voice
  1501→        if (videoAnalysis || voiceAnalysis) {
  1502→          const textScore = feedback.overall_score || 5;
  1503→          const presScore = videoAnalysis?.overall_presentation || textScore;
  1504→          const voiceScore = voiceAnalysis?.overall_voice_score || textScore;
  1505→          feedback.overall_score = Math.round((textScore * 0.5 + presScore * 0.25 + voiceScore * 0.25) * 10) / 10;
  1506→        }
  1507→
  1508→        // Update DB with enriched feedback
  1509→        await pool.query(
  1510→          `UPDATE mock_interview_sessions SET overall_score = $1, overall_feedback = $2 WHERE id = $3`,
  1511→          [feedback.overall_score, JSON.stringify(feedback), bgSessionId]
  1512→        );
  1513→        console.log(`[mock-end-bg] Background analysis complete for session ${bgSessionId}`);
  1514→      } catch (bgErr) {
  1515→        console.error('[mock-end-bg] Background analysis error:', bgErr.message);
  1516→      }
  1517→    })();
  1518→  } catch (err) {
  1519→    console.error('End mock interview error:', err);
  1520→    res.status(500).json({ error: 'Failed to generate feedback' });
  1521→  }
  1522→});
