  1690→// Voice response endpoint — candidate audio → Whisper transcription → AI response → TTS audio
  1691→router.post('/mock/:sessionId/voice-respond', authMiddleware, upload.single('audio'), async (req, res) => {
  1692→  try {
  1693→    const sessionId = req.params.sessionId;
  1694→
  1695→    // BUG FIX: Validate sessionId is a valid integer (prevents "undefined" SQL errors)
  1696→    if (!sessionId || sessionId === 'undefined' || sessionId === 'null' || isNaN(parseInt(sessionId))) {
  1697→      return res.status(400).json({ error: 'Invalid session. Please restart the interview.' });
  1698→    }
  1699→
  1700→    // Get session
  1701→    const sessionResult = await pool.query(
  1702→      'SELECT * FROM mock_interview_sessions WHERE id = $1 AND user_id = $2 AND status = $3',
  1703→      [parseInt(sessionId), req.user.id, 'in_progress']
  1704→    );
  1705→
  1706→    if (sessionResult.rows.length === 0) {
  1707→      return res.status(404).json({ error: 'Session not found or already completed' });
  1708→    }
  1709→
  1710→    const session = sessionResult.rows[0];
  1711→    const conversation = session.conversation || [];
  1712→    const questionIds = session.question_ids || [];
  1713→
  1714→    // Step 1: Transcribe audio with Whisper (with client-side SpeechRecognition fallback)
  1715→    // The client sends the live SpeechRecognition transcript alongside the audio as a fallback
  1716→    const clientTranscript = (req.body.response_text || '').trim();
  1717→    let transcribedText = '';
  1718→    let usedFallback = false;
  1719→
  1720→    if (req.file) {
  1721→      // Audio file uploaded as multipart — use ASR fallback chain (Whisper → NIM Parakeet v2 → v3)
  1722→      const baseMime = (req.file.mimetype || 'audio/webm').split(';')[0];
  1723→      const ext = baseMime.includes('mp4') ? 'mp4' : baseMime.includes('ogg') ? 'ogg' : 'webm';
  1724→      const filename = `recording.${ext}`;
  1725→      console.log(`[voice-respond] Received file: ${req.file.size} bytes, mime: ${req.file.mimetype}, client transcript: ${clientTranscript.length} chars`);
  1726→
  1727→      try {
  1728→        // Use the full ASR fallback chain (OpenAI Whisper → NIM Parakeet v2 → NIM Parakeet v3)
  1729→        const asrResult = await aiProvider.transcribeAudio(
  1730→          req.file.buffer,
  1731→          filename,
  1732→          baseMime,
  1733→          { subscriptionId: req.user.stripe_subscription_id }
  1734→        );
  1735→        if (asrResult && asrResult.text) {
  1736→          transcribedText = asrResult.text.trim();
  1737→          console.log(`[voice-respond] ASR transcription: "${transcribedText.substring(0, 100)}..."`);
  1738→        } else if (clientTranscript.length >= 10) {
  1739→          // ASR returned nothing — use client transcript
  1740→          transcribedText = clientTranscript;
  1741→          usedFallback = true;
  1742→          console.log(`[voice-respond] ASR empty, using client transcript`);
  1743→        }
  1744→      } catch (asrErr) {
  1745→        console.error('[voice-respond] ASR fallback chain failed:', asrErr.message);
  1746→        // All ASR providers failed — fall back to client-side SpeechRecognition transcript
  1747→        if (clientTranscript.length >= 10) {
  1748→          transcribedText = clientTranscript;
  1749→          usedFallback = true;
  1750→          console.log(`[voice-respond] Using client SpeechRecognition fallback: "${transcribedText.substring(0, 100)}..."`);
  1751→        }
  1752→      }
  1753→    } else if (req.body.audio_base64) {
  1754→      const whisperResult = await transcribeAudioWithWhisper(req.body.audio_base64, {
  1755→        subscriptionId: req.user.stripe_subscription_id
  1756→      });
  1757→      if (whisperResult && whisperResult.text) {
  1758→        transcribedText = whisperResult.text.trim();
  1759→      }
  1760→    } else if (clientTranscript.length >= 5) {
  1761→      // Client-side transcript only (no audio file)
  1762→      transcribedText = clientTranscript;
  1763→      usedFallback = true;
  1764→    }
  1765→
  1766→    // BUG FIX: Whisper hallucinates known phrases on silent/near-silent audio
  1767→    const WHISPER_HALLUCINATIONS = [
  1768→      'ご視聴ありがとうございました', '視聴ありがとうございました', 'ありがとうございました',
  1769→      'ご視聴ありがとうございます', '字幕', 'サブスクライブ', 'チャンネル登録',
  1770→      '谢谢观看', '感谢观看', 'Sous-titres', 'Sottotitoli', 'Untertitel',
  1771→      'Thanks for watching', 'Thank you for watching', 'Please subscribe', 'Like and subscribe',
  1772→    ];
  1773→    const isHallucination = !usedFallback && WHISPER_HALLUCINATIONS.some(phrase =>
  1774→      transcribedText.toLowerCase().includes(phrase.toLowerCase())
  1775→    );
  1776→    if (isHallucination) {
  1777→      console.log(`[voice-respond] Filtered Whisper hallucination: "${transcribedText}"`);
  1778→      // Try client transcript before rejecting
  1779→      if (clientTranscript.length >= 10) {
  1780→        transcribedText = clientTranscript;
  1781→        usedFallback = true;
  1782→      } else {
  1783→        return res.status(400).json({ error: 'I didn\'t catch that. Could you please repeat your answer.' });
  1784→      }
  1785→    }
  1786→
  1787→    if (!transcribedText || transcribedText.length < 5) {
  1788→      return res.status(400).json({ error: 'Could not transcribe your response. Please try speaking louder and more clearly.' });
  1789→    }
  1790→
  1791→    // Step 2: Add candidate response to conversation
  1792→    const candidateMessage = {
  1793→      role: 'candidate',
  1794→      text: transcribedText,
  1795→      timestamp: new Date().toISOString()
  1796→    };
  1797→    conversation.push(candidateMessage);
  1798→
  1799→    // Step 3: Get base questions and AI response (with fallback)
  1800→    const questionsResult = await pool.query(
  1801→      'SELECT * FROM question_bank WHERE id = ANY($1)',
  1802→      [questionIds]
  1803→    );
  1804→    const questionMap = {};
  1805→    questionsResult.rows.forEach(q => { questionMap[q.id] = q; });
  1806→    const baseQuestions = questionIds.map(id => questionMap[id]).filter(Boolean);
  1807→
  1808→    // BUG FIX: Wrap with 20s overall timeout — the LLM chain can take 135s (9 providers × 15s each),
  1809→    // but Render kills the request at ~30s. Without this, the scripted fallback never fires.
  1810→    let aiTurn;
  1811→    try {
  1812→      aiTurn = await withTimeout(
  1813→        conductInterviewTurn(
  1814→          conversation,
  1815→          baseQuestions,
  1816→          session.current_question_index,
  1817→          session.target_role,
  1818→          { subscriptionId: req.user.stripe_subscription_id }
  1819→        ),
  1820→        20000,
  1821→        'Voice interview AI turn generation'
  1822→      );
  1823→    } catch (aiErr) {
  1824→      console.warn(`[voice-respond] AI turn generation failed (${aiErr.message}), using scripted fallback`);
  1825→      const nextIdx = session.current_question_index + 1;
  1826→      const nextQ = baseQuestions[nextIdx];
  1827→      const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1828→      if (nextQ && candidateTurnCount < 8) {
  1829→        aiTurn = {
  1830→          reaction: "Thank you for that response.",
  1831→          action: 'transition',
  1832→          question: nextQ.question_text,
  1833→          score_hint: null,
  1834→          notes: 'AI unavailable — scripted transition'
  1835→        };
  1836→      } else {
  1837→        aiTurn = {
  1838→          reaction: "Thank you for sharing all of that.",
  1839→          action: 'wrap_up',
  1840→          question: "Is there anything else you'd like to add before we wrap up?",
  1841→          score_hint: null,
  1842→          notes: 'AI unavailable — scripted wrap-up'
  1843→        };
  1844→      }
  1845→    }
  1846→
  1847→    // Build interviewer message
  1848→    let interviewerText = aiTurn.reaction || '';
  1849→    if (aiTurn.question) {
  1850→      interviewerText += (interviewerText ? '\n\n' : '') + aiTurn.question;
  1851→    }
  1852→
  1853→    const interviewerMessage = {
  1854→      role: 'interviewer',
  1855→      text: interviewerText,
  1856→      action: aiTurn.action || 'transition',
  1857→      score_hint: aiTurn.score_hint || null,
  1858→      notes: aiTurn.notes || null,
  1859→      timestamp: new Date().toISOString()
  1860→    };
  1861→    conversation.push(interviewerMessage);
  1862→
  1863→    // Step 4: Update session in DB
  1864→    const isWrappingUp = aiTurn.action === 'wrap_up';
  1865→    const isTransition = aiTurn.action === 'transition';
  1866→    const newQuestionIndex = isTransition
  1867→      ? Math.min(session.current_question_index + 1, baseQuestions.length)
  1868→      : session.current_question_index;
  1869→    const newFollowUps = (aiTurn.action === 'follow_up' || aiTurn.action === 'challenge')
  1870→      ? (session.follow_ups_asked || 0) + 1
  1871→      : session.follow_ups_asked || 0;
  1872→
  1873→    if (isTransition && newQuestionIndex < baseQuestions.length) {
  1874→      const nextQ = baseQuestions[newQuestionIndex];
  1875→      if (nextQ) {
  1876→        await pool.query('UPDATE question_bank SET times_used = times_used + 1 WHERE id = $1', [nextQ.id]);
  1877→      }
  1878→    }
  1879→
  1880→    await pool.query(
  1881→      `UPDATE mock_interview_sessions
  1882→       SET conversation = $1, current_question_index = $2,
  1883→           questions_asked = $3, follow_ups_asked = $4
  1884→       WHERE id = $5`,
  1885→      [
  1886→        JSON.stringify(conversation),
  1887→        newQuestionIndex,
  1888→        isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1889→        newFollowUps,
  1890→        sessionId
  1891→      ]
  1892→    );
  1893→
  1894→    // BUG FIX: Pre-generate feedback in background after 3+ candidate turns (same as text respond)
  1895→    const voiceCandidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1896→    if (voiceCandidateTurnCount >= 3 && !isWrappingUp) {
  1897→      generateSessionFeedback(conversation, session.target_role, { subscriptionId: req.user.stripe_subscription_id })
  1898→        .then(feedback => {
  1899→          pool.query(
  1900→            `UPDATE mock_interview_sessions SET cached_feedback = $1 WHERE id = $2 AND status = 'in_progress'`,
  1901→            [JSON.stringify(feedback), sessionId]
  1902→          ).catch(() => {});
  1903→          console.log(`[voice-respond] Background feedback cached for session ${sessionId} (${voiceCandidateTurnCount} turns)`);
  1904→        })
  1905→        .catch(err => console.warn('[voice-respond] Background feedback generation failed:', err.message));
  1906→    }
  1907→
  1908→    // Step 5: Generate TTS for interviewer response (8s timeout — TTS chain is 2 providers × 8s max)
  1909→    let audioBase64 = null;
