    const libraryQuestion = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
    const keyPoints = libraryQuestion ? libraryQuestion.key_points : ['Content quality', 'Structure', 'Clarity', 'Relevance'];

